import { useState } from 'react';

import Button from '@mui/material/Button';
import Stack from '@mui/material/Stack';
import Tab from '@mui/material/Tab';
import Tabs from '@mui/material/Tabs';

import DownloadOutlined from '@ant-design/icons/DownloadOutlined';

import apiClient from 'lib/http/apiClient';
import useToast from 'app/providers/useToast';
import CrudResourceModule from 'features/shared/components/CrudResourceModule';
import useSelectOptions from 'features/shared/useSelectOptions';

function TabPanel({ value, index, children }) {
  if (value !== index) return null;
  return <div>{children}</div>;
}

export default function SupervisorPage() {
  const [tab, setTab] = useState(0);
  const { showToast } = useToast();
  const userOptions = useSelectOptions('/users/', (user) => `${user.username} (${user.role})`);
  const shiftOptions = useSelectOptions('/supervisor/shifts/', (shift) => shift.name);
  const ownerOptions = useSelectOptions(
    '/maps/parcel-options/',
    (owner) => `${owner.parcel_code} - ${owner.full_name || 'Sin propietario'} (${owner.rut || 'Sin RUT'})`,
    { include_inactive: 'true' }
  );

  const downloadNotificationsCsv = async () => {
    try {
      const response = await apiClient.get('/supervisor/notifications/export_csv/', { responseType: 'blob' });
      const blobUrl = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = blobUrl;
      link.setAttribute('download', 'notificaciones.csv');
      document.body.appendChild(link);
      link.click();
      link.remove();
      showToast('CSV descargado.', 'success');
    } catch {
      showToast('No se pudo exportar el CSV.', 'error');
    }
  };

  return (
    <Stack sx={{ gap: 2 }}>
      <Stack direction="row" sx={{ justifyContent: 'space-between', alignItems: 'center' }}>
        <Tabs value={tab} onChange={(_, value) => setTab(value)}>
          <Tab label="Turnos" />
          <Tab label="Rondas" />
          <Tab label="Notificaciones/Multas" />
        </Tabs>
        {tab === 2 ? (
          <Button startIcon={<DownloadOutlined />} variant="outlined" onClick={downloadNotificationsCsv}>
            Exportar CSV
          </Button>
        ) : null}
      </Stack>

      <TabPanel value={tab} index={0}>
        <CrudResourceModule
          title="Turnos"
          path="/supervisor/shifts/"
          columns={[
            { key: 'name', label: 'Nombre' },
            { key: 'supervisor', label: 'Supervisor' },
            { key: 'start_datetime', label: 'Inicio' },
            { key: 'end_datetime', label: 'Fin' },
            { key: 'status', label: 'Estado' }
          ]}
          fields={() => [
            { name: 'name', label: 'Nombre', required: true },
            { name: 'supervisor', label: 'Supervisor', type: 'select', options: [{ value: '', label: 'Sin supervisor' }, ...userOptions] },
            { name: 'start_datetime', label: 'Inicio', type: 'datetime-local', required: true },
            { name: 'end_datetime', label: 'Fin', type: 'datetime-local' },
            {
              name: 'status',
              label: 'Estado',
              type: 'select',
              options: [
                { value: 'open', label: 'Abierto' },
                { value: 'closed', label: 'Cerrado' }
              ],
              required: true
            },
            { name: 'notes', label: 'Notas', type: 'textarea', fullWidth: true }
          ]}
          mapPayload={(values) => ({ ...values, supervisor: values.supervisor || null })}
          defaultOrdering="-start_datetime"
        />
      </TabPanel>

      <TabPanel value={tab} index={1}>
        <CrudResourceModule
          title="Rondas"
          path="/supervisor/rounds/"
          columns={[
            { key: 'shift', label: 'Turno' },
            { key: 'guard', label: 'Guardia' },
            { key: 'started_at', label: 'Inicio' },
            { key: 'ended_at', label: 'Fin' },
            { key: 'status', label: 'Estado' }
          ]}
          fields={() => [
            { name: 'shift', label: 'Turno', type: 'select', options: shiftOptions, required: true },
            { name: 'guard', label: 'Guardia', type: 'select', options: [{ value: '', label: 'Sin guardia' }, ...userOptions] },
            { name: 'started_at', label: 'Inicio', type: 'datetime-local', required: true },
            { name: 'ended_at', label: 'Fin', type: 'datetime-local' },
            {
              name: 'status',
              label: 'Estado',
              type: 'select',
              options: [
                { value: 'planned', label: 'Planificada' },
                { value: 'in_progress', label: 'En curso' },
                { value: 'completed', label: 'Completada' }
              ],
              required: true
            },
            { name: 'notes', label: 'Notas', type: 'textarea', fullWidth: true }
          ]}
          mapPayload={(values) => ({ ...values, guard: values.guard || null })}
          defaultOrdering="-started_at"
        />
      </TabPanel>

      <TabPanel value={tab} index={2}>
        <CrudResourceModule
          title="Notificaciones / Multas"
          path="/supervisor/notifications/"
          columns={[
            { key: 'title', label: 'Titulo' },
            { key: 'owner_display', label: 'Propietario' },
            { key: 'amount', label: 'Monto' },
            { key: 'status', label: 'Estado' },
            { key: 'issued_at', label: 'Fecha emision' }
          ]}
          fields={() => [
            { name: 'owner', label: 'Propietario', type: 'select', options: ownerOptions, required: true },
            { name: 'shift', label: 'Turno', type: 'select', options: [{ value: '', label: 'Sin turno' }, ...shiftOptions] },
            { name: 'title', label: 'Titulo', required: true },
            { name: 'description', label: 'Descripcion', type: 'textarea', fullWidth: true },
            { name: 'amount', label: 'Monto', type: 'number', required: true },
            {
              name: 'status',
              label: 'Estado',
              type: 'select',
              options: [
                { value: 'pending', label: 'Pendiente' },
                { value: 'paid', label: 'Pagada' },
                { value: 'cancelled', label: 'Anulada' }
              ],
              required: true
            },
            { name: 'issued_at', label: 'Fecha emision', type: 'datetime-local', required: true },
            { name: 'due_date', label: 'Fecha vencimiento', type: 'date' },
            { name: 'paid_at', label: 'Fecha pago', type: 'datetime-local' }
          ]}
          mapPayload={(values) => ({ ...values, shift: values.shift || null })}
          defaultOrdering="-issued_at"
        />
      </TabPanel>
    </Stack>
  );
}

